IStyle addNewUserStyle(final boolean copyStyleFromSelected){
  final String styleName=JOptionPane.showInputDialog(KeyboardFocusManager.getCurrentKeyboardFocusManager().getFocusOwner(),TextUtils.getText("enter_new_style_name"),"");
  if (styleName == null || styleName.isEmpty()) {
    return null;
