public static Set<Class<?>> findClassesAssignableFromPath(String packagePath,Class<?> assignableFrom,ClassLoader cl) throws IOException, ClassNotFoundException {
  Set<Class<?>> classes=new HashSet<>();
  URL resource=cl.getResource(packagePath);
  if (resource == null)   return classes;
  String filePath=resource.getFile();
  if (filePath == null)   return classes;
  File f=new File(filePath);
  if (f.isDirectory()) {
    for (    String file : f.list()) {
      File ff=new File(f,file);
      if (ff.isDirectory()) {
        String dirname=packagePath + File.separator + file;
        Set<Class<?>> clazzes=findClassesAssignableFromPath(dirname,assignableFrom,cl);
        classes.addAll(clazzes);
        continue;
      }
      if (file.endsWith(".class")) {
        String name=packagePath + File.separator + file.substring(0,file.indexOf(".class"));
        name=name.replace(File.separator,".");
        try {
          Class<?> clazz=Class.forName(name);
          if (!assignableFrom.equals(clazz) && assignableFrom.isAssignableFrom(clazz))           classes.add(clazz);
        }
 catch (        ClassNotFoundException ignored) {
        }
      }
    }
  }
  return classes;
}

