  if (!isParameterized())   addresses.add(getInetAddress(getConvertedValue()));
 else {
    List<?> values=(List<?>)getConvertedValue();
    if (values.isEmpty())     return addresses;
    for (int i=0; i < values.size(); i++)     addresses.add(getInetAddress(values.get(i)));
  }
  return addresses;
}

