public OkHttpResponse(OkHttp okhttp,URL url,CrawlDatum datum) throws ProtocolException, IOException {
  this.url=url;
  Request.Builder rb=new Request.Builder().url(url);
  rb.header(USER_AGENT,okhttp.getUserAgent());
  okhttp.getCustomRequestHeaders().forEach((k) -> {
    rb.header(k[0],k[1]);
  }
);
  if (okhttp.isIfModifiedSinceEnabled() && datum.getModifiedTime() > 0) {
    rb.header(IF_MODIFIED_SINCE,HttpDateFormat.toString(datum.getModifiedTime()));
  }
  if (okhttp.isCookieEnabled()) {
    String cookie=null;
    if (datum.getMetaData().containsKey(HttpBase.COOKIE)) {
      cookie=((Text)datum.getMetaData().get(HttpBase.COOKIE)).toString();
    }
    if (cookie == null) {
      cookie=okhttp.getCookie(url);
    }
    if (cookie != null) {
      rb.header("Cookie",cookie);
    }
  }
  Request request=rb.build();
  okhttp3.Call call=okhttp.getClient().newCall(request);
  try (okhttp3.Response response=call.execute()){
    Metadata responsemetadata=new Metadata();
    okhttp3.Headers httpHeaders=response.headers();
    for (int i=0, size=httpHeaders.size(); i < size; i++) {
      String key=httpHeaders.name(i);
      String value=httpHeaders.value(i);
      if (key.equals(REQUEST) || key.equals(RESPONSE_HEADERS)) {
        value=new String(Base64.getDecoder().decode(value));
      }
      responsemetadata.add(key,value);
    }
    LOG.debug("{} - {} {} {}",url,response.protocol(),response.code(),response.message());
    TruncatedContent truncated=new TruncatedContent();
    this.content=toByteArray(response.body(),truncated,okhttp.getMaxContent(),okhttp.getMaxDuration(),okhttp.isStorePartialAsTruncated());
    responsemetadata.add(FETCH_TIME,Long.toString(System.currentTimeMillis()));
    if (truncated.booleanValue()) {
      if (!call.isCanceled()) {
        call.cancel();
      }
      responsemetadata.set(TRUNCATED_CONTENT,"true");
      responsemetadata.set(TRUNCATED_CONTENT_REASON,truncated.getReason().toString().toLowerCase(Locale.ROOT));
      LOG.debug("HTTP content truncated to {} bytes (reason: {})",this.content.length,truncated.getReason());
    }
    this.code=response.code();
    this.headers=responsemetadata;
  }
 }

