public static void waitUntilAllChannelsHaveSameView(long timeout,long interval,JChannel... channels) throws TimeoutException {
  if (interval >= timeout || timeout <= 0)   throw new IllegalArgumentException("interval needs to be smaller than timeout or timeout needs to be > 0");
  if (channels == null || channels.length == 0)   return;
  long target_time=System.currentTimeMillis() + timeout;
  while (System.currentTimeMillis() <= target_time) {
    boolean all_channels_have_correct_view=true;
    View first=channels[0].getView();
    for (    JChannel ch : channels) {
      View view=ch.getView();
      if (first == null || !Objects.equals(view,first) || view.size() != channels.length) {
        all_channels_have_correct_view=false;
        break;
      }
    }
    if (all_channels_have_correct_view)     return;
    Util.sleep(interval);
  }
  View[] views=new View[channels.length];
  StringBuilder sb=new StringBuilder();
  for (int i=0; i < channels.length; i++) {
    views[i]=channels[i].getView();
    sb.append(channels[i].getName()).append(": ").append(views[i]).append("\n");
  }
  View first=channels[0].getView();
  for (  View view : views)   if (view == null || !Objects.equals(view,first) || view.size() != channels.length)   throw new TimeoutException("Timeout " + timeout + " kicked in, views are:\n"+ sb);
}
public static void waitUntilAllChannelsHaveSameView(long timeout,long interval,Collection<JChannel> channels) throws TimeoutException {
  JChannel[] tmp=new JChannel[channels != null ? channels.size() : 0];
  if (tmp == null)   return;
  int index=0;
  for (Iterator<JChannel> it=channels.iterator(); it.hasNext(); )   tmp[index++]=it.next();
  waitUntilAllChannelsHaveSameView(timeout,interval,tmp);
}

