    NutchJob.cleanupAfterFailure(outPath,lock,fs);
    throw e;
  }
  long end=System.currentTimeMillis();
  LOG.info("CrawlDb merge: finished at " + sdf.format(end) + ", elapsed: "+ TimingUtil.elapsedTime(start,end));
